SELECT q.question_text, m.metric_name
FROM survey_questions q
INNER JOIN health_metrics m ON q.question_id = m.survey_id;

SELECT hm.metric_name, AVG(hm.metric_value) AS average_metric_value
FROM health_metrics hm
GROUP BY hm.metric_name;

WITH UsersWithSurveyResponses AS (
  SELECT DISTINCT user_id FROM survey_responses
),
UsersWithAccessLogs AS (
  SELECT DISTINCT user_id FROM access_logs
)
SELECT u.user_name
FROM users u
WHERE u.user_id IN (SELECT user_id FROM UsersWithSurveyResponses) 
AND u.user_id NOT IN (SELECT user_id FROM UsersWithAccessLogs);

SELECT access_type 
FROM access_logs 
WHERE access_id = 0;

SELECT age_group_name, education_name
FROM age_groups, education_levels
WHERE age_group_name = '25-34' AND education_name = 'Master or doctorate';

SELECT question_text
FROM survey_questions
WHERE question_type = 'multiple choice';

SELECT city_id, city_name, region, population
FROM cities
WHERE city_id > 5 AND population > 100000;

SELECT u.user_name, a.age_group_name
FROM users AS u, age_groups AS a
WHERE u.user_id = 0 AND a.age_group_id = 0;

SELECT metric_name 
FROM health_metrics 
ORDER BY metric_value DESC;
